import { useEffect, useMemo, useState } from "react";
import { Link, useNavigate, useParams } from "react-router-dom";
import Button from "../components/Button";
import ProductCard from "../components/ProductCard";
import RatingStars from "../components/RatingStars";
import { useCart } from "../context/CartContext";
import { products } from "../data/products";

function ProductDetails() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { addToCart } = useCart();
  const [quantity, setQuantity] = useState(1);

  const product = useMemo(
    () => products.find((entry) => entry.id === id),
    [id]
  );
  const [selectedImage, setSelectedImage] = useState(product?.images[0] || "");

  useEffect(() => {
    if (product) {
      setSelectedImage(product.images[0]);
    }
  }, [product]);

  if (!product) {
    return (
      <div className="mx-auto max-w-7xl px-4 py-16 text-center sm:px-6 lg:px-8">
        <h1 className="text-2xl font-bold text-slate-900">Product Not Found</h1>
        <p className="mt-2 text-slate-500">
          The product you are looking for does not exist.
        </p>
        <Link
          className="mt-6 inline-flex rounded-xl bg-primary-600 px-5 py-2.5 text-sm font-semibold text-white"
          to="/shop"
        >
          Back to Shop
        </Link>
      </div>
    );
  }

  const relatedProducts = products
    .filter((entry) => entry.category === product.category && entry.id !== product.id)
    .slice(0, 4);

  const handleBuyNow = () => {
    addToCart(product, quantity);
    navigate("/checkout");
  };

  return (
    <div className="mx-auto max-w-7xl space-y-10 px-4 py-8 sm:px-6 lg:px-8">
      <section className="grid gap-8 lg:grid-cols-2">
        <div className="space-y-4">
          <div className="overflow-hidden rounded-xl border border-slate-100 bg-white shadow-md">
            <img
              alt={product.title}
              className="h-[420px] w-full object-cover sm:h-[500px]"
              src={selectedImage}
            />
          </div>
          <div className="grid grid-cols-4 gap-3">
            {product.images.map((image) => (
              <button
                className={`overflow-hidden rounded-xl border ${
                  selectedImage === image
                    ? "border-primary-500 ring-2 ring-primary-100"
                    : "border-slate-200"
                }`}
                key={image}
                onClick={() => setSelectedImage(image)}
                type="button"
              >
                <img
                  alt={`${product.title} thumbnail`}
                  className="h-20 w-full object-cover"
                  src={image}
                />
              </button>
            ))}
          </div>
        </div>

        <div className="rounded-xl border border-slate-100 bg-white p-6 shadow-md sm:p-8">
          <p className="text-sm font-semibold uppercase tracking-wide text-primary-600">
            {product.category}
          </p>
          <h1 className="mt-2 text-3xl font-bold text-slate-900">{product.title}</h1>
          <div className="mt-3">
            <RatingStars rating={product.rating} />
          </div>
          <p className="mt-4 text-3xl font-bold text-slate-900">${product.price}</p>
          <p className="mt-4 text-sm leading-7 text-slate-600">{product.description}</p>

          <div className="mt-8">
            <p className="text-sm font-semibold text-slate-700">Quantity</p>
            <div className="mt-3 inline-flex items-center rounded-xl border border-slate-200">
              <button
                className="px-4 py-2 text-lg text-slate-600 hover:bg-slate-50"
                onClick={() => setQuantity((current) => Math.max(1, current - 1))}
                type="button"
              >
                -
              </button>
              <span className="min-w-10 text-center text-sm font-semibold">{quantity}</span>
              <button
                className="px-4 py-2 text-lg text-slate-600 hover:bg-slate-50"
                onClick={() => setQuantity((current) => current + 1)}
                type="button"
              >
                +
              </button>
            </div>
          </div>

          <div className="mt-8 flex flex-wrap gap-3">
            <Button onClick={() => addToCart(product, quantity)} variant="primary">
              Add to Cart
            </Button>
            <Button onClick={handleBuyNow} variant="secondary">
              Buy Now
            </Button>
          </div>
        </div>
      </section>

      <section>
        <h2 className="mb-4 text-xl font-bold text-slate-900">Related Products</h2>
        <div className="grid gap-5 sm:grid-cols-2 xl:grid-cols-4">
          {relatedProducts.map((relatedProduct) => (
            <ProductCard key={relatedProduct.id} product={relatedProduct} />
          ))}
        </div>
      </section>
    </div>
  );
}

export default ProductDetails;
